using System;
using System.Diagnostics;
using System.Drawing;
using System.IO;
using System.Windows.Forms;

namespace SR160Setup
{
    class SetupForm : Form
    {
        private TextBox txtPath;
        private CheckBox chkDesktop;
        private Button btnInstall;
        private Button btnBrowse;
        private Label lblProgress;
        private ProgressBar progress;

        public SetupForm()
        {
            Text = "CHIPMO - SR160 Power Config Setup";
            ClientSize = new Size(480, 340);
            FormBorderStyle = FormBorderStyle.FixedDialog;
            MaximizeBox = false;
            StartPosition = FormStartPosition.CenterScreen;
            Font = new Font("Segoe UI", 9);

            var pnlHeader = new Panel
            {
                Dock = DockStyle.Top,
                Height = 70,
                BackColor = Color.FromArgb(33, 37, 41)
            };

            var lblTitle = new Label
            {
                Text = "CHIPMO",
                Location = new Point(20, 8),
                AutoSize = true,
                Font = new Font("Segoe UI", 18, FontStyle.Bold),
                ForeColor = Color.White
            };

            var lblSub = new Label
            {
                Text = "Chainway SR160 UHF RFID - TX Power \u0442\u043E\u0445\u0438\u0440\u0443\u0443\u043B\u0430\u0433\u0447 \u0441\u0443\u0443\u043B\u0433\u0430\u0445",
                Location = new Point(20, 42),
                AutoSize = true,
                Font = new Font("Segoe UI", 9),
                ForeColor = Color.FromArgb(173, 181, 189)
            };

            pnlHeader.Controls.AddRange(new Control[] { lblTitle, lblSub });

            var lblPath = new Label
            {
                Text = "\u0421\u0443\u0443\u043B\u0433\u0430\u0445 \u0437\u0430\u043C:",
                Location = new Point(20, 90),
                AutoSize = true
            };

            string defaultPath = Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles),
                "CHIPMO", "SR160PowerConfig");

            txtPath = new TextBox
            {
                Location = new Point(20, 110),
                Size = new Size(350, 25),
                Text = defaultPath
            };

            btnBrowse = new Button
            {
                Text = "...",
                Location = new Point(376, 109),
                Size = new Size(80, 25)
            };
            btnBrowse.Click += delegate
            {
                var dlg = new FolderBrowserDialog();
                dlg.Description = "\u0421\u0443\u0443\u043B\u0433\u0430\u0445 \u0445\u0430\u0432\u0442\u0430\u0441 \u0441\u043E\u043D\u0433\u043E\u043D\u043E \u0443\u0443:";
                if (dlg.ShowDialog() == DialogResult.OK)
                    txtPath.Text = dlg.SelectedPath;
            };

            chkDesktop = new CheckBox
            {
                Text = "\u0428\u0438\u0440\u044D\u044D\u043D\u0438\u0439 \u0442\u043E\u0432\u0447\u043B\u043E\u043B \u04AF\u04AF\u0441\u0433\u044D\u0445",
                Location = new Point(20, 150),
                AutoSize = true,
                Checked = true
            };

            var grpInfo = new GroupBox
            {
                Text = "\u041C\u044D\u0434\u044D\u044D\u043B\u044D\u043B",
                Location = new Point(20, 185),
                Size = new Size(436, 70)
            };

            var lblInfo = new Label
            {
                Text = "\u041A\u043E\u043C\u043F\u0430\u043D\u0438: CHIPMO\n"
                     + "\u0422\u04E9\u0445\u04E9\u04E9\u0440\u04E9\u043C\u0436: Chainway SR160 UHF RFID Reader\n"
                     + "\u0425\u04AF\u0447\u0438\u043D: v1.0 \u2014 TX Power \u0442\u043E\u0445\u0438\u0440\u0443\u0443\u043B\u0430\u0433\u0447",
                Location = new Point(12, 18),
                AutoSize = true,
                Font = new Font("Segoe UI", 8)
            };
            grpInfo.Controls.Add(lblInfo);

            progress = new ProgressBar
            {
                Location = new Point(20, 268),
                Size = new Size(436, 20),
                Visible = false
            };

            lblProgress = new Label
            {
                Text = "",
                Location = new Point(20, 292),
                AutoSize = true
            };

            btnInstall = new Button
            {
                Text = "\u0421\u0443\u0443\u043B\u0433\u0430\u0445",
                Location = new Point(330, 298),
                Size = new Size(126, 35),
                Font = new Font("Segoe UI", 11, FontStyle.Bold),
                BackColor = Color.FromArgb(76, 175, 80),
                ForeColor = Color.White,
                FlatStyle = FlatStyle.Flat
            };
            btnInstall.FlatAppearance.BorderSize = 0;
            btnInstall.Click += BtnInstall_Click;

            Controls.AddRange(new Control[] {
                pnlHeader, lblPath, txtPath, btnBrowse,
                chkDesktop, grpInfo, progress, lblProgress, btnInstall
            });
        }

        private void BtnInstall_Click(object sender, EventArgs e)
        {
            string targetDir = txtPath.Text.Trim();
            if (targetDir.Length == 0)
            {
                MessageBox.Show("\u0421\u0443\u0443\u043B\u0433\u0430\u0445 \u0437\u0430\u043C \u043E\u0440\u0443\u0443\u043B\u043D\u0430 \u0443\u0443!", "\u0410\u043B\u0434\u0430\u0430",
                    MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }

            btnInstall.Enabled = false;
            btnBrowse.Enabled = false;
            txtPath.Enabled = false;
            progress.Visible = true;
            progress.Value = 0;

            try
            {
                Directory.CreateDirectory(targetDir);
                progress.Value = 10;
                lblProgress.Text = "\u0424\u0430\u0439\u043B\u0443\u0443\u0434 \u0445\u0443\u0443\u043B\u0436 \u0431\u0430\u0439\u043D\u0430...";
                Application.DoEvents();

                WriteFile(targetDir, "SR160PowerConfig.exe", AppData.EXE);
                progress.Value = 40;
                Application.DoEvents();

                WriteFile(targetDir, "UHFAPI.dll", AppData.API);
                progress.Value = 70;
                Application.DoEvents();

                WriteFile(targetDir, "libusb-1.0.dll", AppData.USB);
                progress.Value = 90;
                Application.DoEvents();

                if (chkDesktop.Checked)
                {
                    lblProgress.Text = "\u0422\u043E\u0432\u0447\u043B\u043E\u043B \u04AF\u04AF\u0441\u0433\u044D\u0436 \u0431\u0430\u0439\u043D\u0430...";
                    Application.DoEvents();
                    CreateShortcut(targetDir);
                }

                progress.Value = 100;
                lblProgress.Text = "\u0410\u043C\u0436\u0438\u043B\u0442\u0442\u0430\u0439 \u0441\u0443\u0443\u043B\u0433\u0430\u043B\u0430\u0430!";

                DialogResult res = MessageBox.Show(
                    "\u041F\u0440\u043E\u0433\u0440\u0430\u043C\u043C \u0430\u043C\u0436\u0438\u043B\u0442\u0442\u0430\u0439 \u0441\u0443\u0443\u043B\u0433\u0430\u0433\u0434\u043B\u0430\u0430!\n\n\u0417\u0430\u043C: " + targetDir
                    + "\n\n\u041E\u0434\u043E\u043E \u043D\u044D\u044D\u0445 \u04AF\u04AF?",
                    "CHIPMO - \u0410\u043C\u0436\u0438\u043B\u0442\u0442\u0430\u0439",
                    MessageBoxButtons.YesNo, MessageBoxIcon.Information);

                if (res == DialogResult.Yes)
                {
                    Process.Start(Path.Combine(targetDir, "SR160PowerConfig.exe"));
                }

                Close();
            }
            catch (Exception ex)
            {
                MessageBox.Show("\u0421\u0443\u0443\u043B\u0433\u0430\u0445\u0430\u0434 \u0430\u043B\u0434\u0430\u0430 \u0433\u0430\u0440\u043B\u0430\u0430:\n" + ex.Message,
                    "\u0410\u043B\u0434\u0430\u0430", MessageBoxButtons.OK, MessageBoxIcon.Error);
                btnInstall.Enabled = true;
                btnBrowse.Enabled = true;
                txtPath.Enabled = true;
            }
        }

        private void WriteFile(string dir, string name, string b64)
        {
            byte[] data = Convert.FromBase64String(b64);
            File.WriteAllBytes(Path.Combine(dir, name), data);
        }

        private void CreateShortcut(string targetDir)
        {
            try
            {
                string desktop = Environment.GetFolderPath(Environment.SpecialFolder.DesktopDirectory);
                string shortcutPath = Path.Combine(desktop, "SR160 Power Config.lnk");
                string targetExe = Path.Combine(targetDir, "SR160PowerConfig.exe");

                string vbs = Path.Combine(Path.GetTempPath(), "create_shortcut.vbs");
                string script = "Set ws = CreateObject(\"WScript.Shell\")\n"
                    + "Set sc = ws.CreateShortcut(\"" + shortcutPath + "\")\n"
                    + "sc.TargetPath = \"" + targetExe + "\"\n"
                    + "sc.WorkingDirectory = \"" + targetDir + "\"\n"
                    + "sc.Description = \"CHIPMO - SR160 Power Config\"\n"
                    + "sc.Save\n";
                File.WriteAllText(vbs, script);

                Process p = new Process();
                p.StartInfo.FileName = "cscript";
                p.StartInfo.Arguments = "//Nologo \"" + vbs + "\"";
                p.StartInfo.WindowStyle = ProcessWindowStyle.Hidden;
                p.Start();
                p.WaitForExit();
                File.Delete(vbs);
            }
            catch { }
        }
    }

    static class AppData
    {
        public const string EXE = "";
        public const string API = "";
        public const string USB = "";
    }

    static class Program
    {
        [STAThread]
        static void Main()
        {
            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.Run(new SetupForm());
        }
    }
}
